sequence.script:
var base = mc.getProperty("req");
var coverageData = mc.getProperty("coveragePayload");

// Parse base
if (typeof base === "string") {
    base = JSON.parse(base);
}

// Parse coverage
if (typeof coverageData === "string") {
    coverageData = JSON.parse(coverageData);
}

//  Ensure coverageData is ALWAYS an array
if (!Array.isArray(coverageData)) {
    coverageData = [coverageData];
}

if (!coverageData) {
    coverageData = [];
}

if (base.claimRequest &&
    base.claimRequest.policy &&
    base.claimRequest.policy.insurableObjects) {

    var objects = base.claimRequest.policy.insurableObjects;

    for (var i = 0; i < objects.length; i++) {
        var obj = objects[i];
        var matchedCoverages = [];

        for (var j = 0; j < coverageData.length; j++) {
            var cov = coverageData[j];

            //  Debug safeguard
            if (!cov) continue;

            if (cov.insurableObjectIdentifier == obj.insurableObjectIdentifier) {
                matchedCoverages.push({
                    coverageIdentifier: cov.coverageIdentifier,
                    coverageName: cov.coverageName,
                    limits: cov.limits,
                    deductibles: cov.deductibles
                });
            }
        }

        obj.coverage = matchedCoverages;
    }
}

mc.setPayloadJSON(base);

var payload = mc.getPayloadJSON();
var req = payload ? payload.claimRequest : null;

var allowedClaimTypes = [
    "OWN_DAMAGE", "THIRD_PARTY", "THEFT", "FIRE",
    "BODILY_INJURY", "THIRD_PARTY_LIABILITY",
    "COLLISION", "ROADSIDE_SERVICE"
];

function isBlank(v) {
    return v === null || v === undefined || String(v).trim() === "";
}

var response = {};

// ==================== MAIN VALIDATION ====================

if (req == null) {
    response = { valid: false, error: "claimRequest is missing" };
}
else if (allowedClaimTypes.indexOf(req.claimType) === -1) {
    response = {
        valid: false,
        error: "claimType must be one of OWN_DAMAGE, THIRD_PARTY, THEFT,FIRE,BODILY_INJURY,THIRD_PARTY_LIABILITY,COLLISION,ROADSIDE_SERVICE"
    };
}
else if (isBlank(req.claimReportedDate)) {
    response = { valid: false, error: "claimReportedDate is mandatory" };
}
else if (isBlank(req.incidentDateTime)) {
    response = { valid: false, error: "incidentDateTime is mandatory" };
}
else if (!req.parties || req.parties.length === 0) {
    response = { valid: false, error: "At least one party is required" };
}
else if (!req.policy || isBlank(req.policy.policyNumber)) {
    response = { valid: false, error: "policyNumber is mandatory" };
}
else if (!req.policy || isBlank(req.policy.productType)) {
    response = { valid: false, error: "productType is mandatory" };
}

// ==================== VEHICLE ====================

else if (!req.policy.insurableObjects || req.policy.insurableObjects.length === 0) {
    response = { valid: false, error: "At least one insurableObject is required" };
}
else if (
    !req.policy.insurableObjects[0].vehicle ||
    isBlank(req.policy.insurableObjects[0].vehicle.vehicleIdentificationNumber)
) {
    response = { valid: false, error: "vehicleIdentificationNumber (VIN) is mandatory" };
}
else if (req.policy.insurableObjects[0].vehicle.vehicleValue == null) {
    response = { valid: false, error: "vehicleValue is mandatory" };
}

// ==================== COVERAGE ====================

else if (
    !req.policy.insurableObjects[0].coverage ||
    req.policy.insurableObjects[0].coverage.length === 0
) {
    response = { valid: false, error: "At least one coverage is required for vehicle" };
}
else if (
    isBlank(req.policy.insurableObjects[0].coverage[0].coverageIdentifier)
) {
    response = { valid: false, error: "coverageIdentifier is mandatory" };
}

// ==================== DRIVER ====================

else if (!req.policy.driverDetails) {
    response = { valid: false, error: "driverDetails is mandatory" };
}
else if (isBlank(req.policy.driverDetails.driverName)) {
    response = { valid: false, error: "driverName is mandatory" };
}
else if (isBlank(req.policy.driverDetails.driverLicenseNumber)) {
    response = { valid: false, error: "driverLicenseNumber is mandatory" };
}

// ==================== POLICE REPORT ====================

else if (
    req.accidentDetails &&
    req.accidentDetails.policeReport &&
    req.accidentDetails.policeReport.reportRegistered === true &&
    (
        isBlank(req.accidentDetails.policeReport.reportNumber) ||
        isBlank(req.accidentDetails.policeReport.policeStation)
    )
) {
    response = {
        valid: false,
        error: "Police report number and police station are mandatory when reportRegistered is true"
    };
}

// ==================== IMAGES ====================

else if (
    !req.accidentDetails ||
    !req.accidentDetails.images ||
    req.accidentDetails.images.length === 0
) {
    response = { valid: false, error: "At least one accident image is required" };
}

// ==================== LOCATION ====================

else if (
    !req.incidentLocation ||
    !req.incidentLocation.address ||
    isBlank(req.incidentLocation.address.addressLine1) ||
    isBlank(req.incidentLocation.address.cityName) ||
    isBlank(req.incidentLocation.address.stateCode) ||
    isBlank(req.incidentLocation.address.countryCode)
) {
    response = { valid: false, error: "Complete incidentLocation address is mandatory" };
}

// ==================== BANK ====================

else if (
    !req.bankDetails ||
    isBlank(req.bankDetails.accountNumber) ||
    isBlank(req.bankDetails.bankName)
) {
    response = { valid: false, error: "Bank accountNumber and bankName are mandatory" };
}

// ==================== CONTACT ====================

else if (
    !req.contactDetails ||
    isBlank(req.contactDetails.email)
) {
    response = { valid: false, error: "Contact email is mandatory" };
}
else if (isBlank(req.contactDetails.phone)) {
    response = { valid: false, error: "Contact phone is mandatory" };
}

// ==================== SUCCESS ====================

else {
    response = { valid: true, error: null };
}

mc.setPayloadJSON(response);

var image = mc.getPayloadJSON();
var uuid = java.util.UUID.randomUUID().toString().replace(/-/g,"");
var docPayload = {
    documentId: "DL-" + uuid,
    fileName: image.fileName,
    contentType: image.contentType,
    data: image.data
};
mc.setPayloadJSON(docPayload);

var currentResponse = mc.getPayloadJSON();

var existing = mc.getProperty("documentResponse");

if (existing == null) {
    existing = [];
} else if (typeof existing === "string") {
    existing = JSON.parse(existing);
}

if (!Array.isArray(existing)) {
    existing = [];
}

existing.push(currentResponse);

mc.setProperty("documentResponse", JSON.stringify(existing), "axis2");

else.script:
var payload = mc.getPayloadJSON();

var epoch = Date.now().toString();
var rand = Math.floor(Math.random() * 1000).toString().padStart(3, "0");

var claimId = "CLM-" + (epoch + rand).slice(-10);

var claimRequest = payload.claimRequest;

claimRequest.claimId = claimId;

// zipCode → pinCode
if (claimRequest.incidentLocation &&
    claimRequest.incidentLocation.address &&
    claimRequest.incidentLocation.address.zipCode) {

    var addr = claimRequest.incidentLocation.address;

    addr.pinCode = addr.zipCode;
    delete addr.zipCode;
}

mc.setPayloadJSON({
    claimRequest: claimRequest
});

sequence.script:
var payload = mc.getPayloadJSON();
var claim = payload.claimRequest;

// ================= GENERATE CLAIM ID =================
var epoch = Date.now().toString();
var rand = Math.floor(Math.random() * 1000).toString();
var rand3 = rand.length < 3 ? ("000".substring(0, 3 - rand.length) + rand) : rand;

var claimId = "CLM-" + (epoch + rand3).slice(-10);

// ================= MAP IMAGES DIRECTLY =================
if (claim.accidentDetails && Array.isArray(claim.accidentDetails.images)) {

    claim.accidentDetails.images = claim.accidentDetails.images.map(function(item) {

        // item is already { documentId, message }
        if (item && item.documentId) {
            return item.documentId;
        }

        // fallback (never null)
        return "DOC-MISSING";
    });
}

// ================= SET CLAIM FIELDS =================
claim.claimId = claimId;

var now = new Date();
var formattedDate = now.toISOString().slice(0,19); // yyyy-MM-ddTHH:mm:ss

claim.claimIntimationDate = formattedDate;
claim.claimStatusCode = "APPLIED";

// ================= ZIP → PIN =================
if (claim.incidentLocation && claim.incidentLocation.address) {

    var addr = claim.incidentLocation.address;

    if (addr.zipCode) {
        addr.pinCode = addr.zipCode;
        delete addr.zipCode;
    }
}

// ================= FINAL PAYLOAD =================
var finalPayload = {
    claimRequest: claim
};

// ================= STORE VARIABLES =================
mc.setProperty("updatedPayload", JSON.stringify(finalPayload));
mc.setProperty("claimIntimationDate", claim.claimIntimationDate);
mc.setProperty("policyId", claim.policy.policyNumber);

// ================= SET OUTPUT =================
mc.setPayloadJSON(finalPayload);

var updatedPayload = mc.getProperty("updatedPayload");
var payload = updatedPayload ? JSON.parse(updatedPayload) : {};
var claim = payload.claimRequest || {};

var claimId = claim.claimId || "";
var policyNumber = (claim.policy || {}).policyNumber || "";
var claimDate = claim.claimIntimationDate || "";

function formatDate(dateInput) {
    if (!dateInput) return "";
    var d = new Date(dateInput);
    return isNaN(d.getTime()) ? dateInput : d.toLocaleString("en-US", {
        month: "long",
        day: "2-digit",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
        hour12: true
    });
}

var nowFormatted = formatDate(new Date());
var formattedClaimDate = formatDate(claimDate);

var subject = "Acknowledgement of Claim " + claimId;
mc.setProperty("Email_Subject", subject);

var emailBody = '<!doctype html>' +
'<html><body>' +
'<h2>Claim Acknowledgement - ' + claimId + '</h2>' +

'<p>' + nowFormatted + '</p>' +
'<p>Dear User,</p>' +

'<p>I am writing on behalf of <strong>Exasure Insurance Integration Cloud</strong> to acknowledge receiving your claim filed on ' +
formattedClaimDate +
' regarding your Personal Auto Insurance policy # ' + policyNumber +
'. Your claim is currently under review.</p>' +
'<p>Sincerely,<br><strong>Exasure IIC</strong></p>' +


'</body></html>';

mc.setProperty("Email_Body", String(emailBody));

// -----------------------------------
// Parse input (vars.updatedPayload)
// -----------------------------------
var updatedPayload = mc.getProperty("updatedPayload");
var payload = {};

try {
    payload = updatedPayload ? JSON.parse(updatedPayload) : {};
} catch (e) {
    payload = {};
}

var claim = payload.claimRequest || {};

// DWL: claim.policy.insurableObjects default []
var insurableObjects = (claim.policy && claim.policy.insurableObjects) || [];

var mappedResult = [];

// -----------------------------------
// Map each insurable object
// -----------------------------------
for (var i = 0; i < insurableObjects.length; i++) {

    var insurableObj = insurableObjects[i];

    var mappedObj = {
        insurableObjectIdentifier: insurableObj.insurableObjectIdentifier,
        coverageStatus: "validated",
        claimType: claim.claimType,
        claimId: claim.claimId,
        coverages: []
    };

    // DWL: (insurableObj.coverage default [])
    var coverages = insurableObj.coverage || [];

    for (var j = 0; j < coverages.length; j++) {

        var coverageObj = coverages[j];

        mappedObj.coverages.push({
            coverageIdentifier: coverageObj.coverageIdentifier,
            coverageName: claim.claimType, // same as DWL
            limits: coverageObj.limits || [],
            deductibles: coverageObj.deductibles || []
        });
    }

    mappedResult.push(mappedObj);
}

// -----------------------------------
// Final output (DWL logic)
// -----------------------------------
var finalPayload = {};

if (mappedResult.length === 0) {
    finalPayload = {};                     // isEmpty
} else if (mappedResult.length === 1) {
    finalPayload = mappedResult[0];        // sizeOf == 1
} else {
    finalPayload = mappedResult;           // multiple
}

// -----------------------------------
// Set payload
// -----------------------------------
mc.setPayloadJSON(finalPayload);
